import{_ as t,o as r,c as a,ao as d}from"./chunks/framework.DGf-9kxS.js";const h=JSON.parse('{"title":"Structural dependence overview","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/structural-dependence.md","filePath":"tutorials/structural-dependence.md","lastUpdated":null}'),o={name:"tutorials/structural-dependence.md"};function l(i,e,n,s,c,p){return r(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="Structural-dependence-overview" tabindex="-1">Structural dependence overview <a class="header-anchor" href="#Structural-dependence-overview" aria-label="Permalink to &quot;Structural dependence overview {#Structural-dependence-overview}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Stable</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/structural-dependence.html" target="_blank" rel="noreferrer">Structural dependence overview</a>. <strong>In DRM.jl today:</strong> all four structured-effect markers on the mean — <code>relmat</code> (supplied <code>K</code>), <code>animal</code> (pedigree <code>A</code>), <code>phylo</code> (tree), and <code>spatial</code> (coordinates) — are fitted in closed form, plus the verified q=4 phylogenetic bivariate engine.</p></div><p>A structured effect puts a <strong>known correlation</strong> among the group-level random intercepts instead of treating groups as independent. The marker names where that correlation comes from:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Marker</th><th style="text-align:right;">Correlation source</th><th style="text-align:right;">Supply</th></tr></thead><tbody><tr><td style="text-align:right;"><code>relmat(1 | id)</code></td><td style="text-align:right;">an arbitrary known matrix <code>K</code></td><td style="text-align:right;"><code>K = …</code></td></tr><tr><td style="text-align:right;"><code>animal(1 | id)</code></td><td style="text-align:right;">an additive-genetic pedigree</td><td style="text-align:right;"><code>A = …</code></td></tr><tr><td style="text-align:right;"><code>phylo(1 | species)</code></td><td style="text-align:right;">a phylogenetic tree</td><td style="text-align:right;"><code>tree = …</code></td></tr><tr><td style="text-align:right;"><code>spatial(1 | site)</code></td><td style="text-align:right;">distance between coordinates</td><td style="text-align:right;"><code>coords = …</code> (range estimated)</td></tr></tbody></table><p>All four reduce to the same closed-form generalised-least-squares marginal <code>V = D + σ_s² Z K Zᵀ</code> (no Laplace needed when the structure is on the mean). Each has its own worked tutorial — see below.</p><h2 id="See-also" tabindex="-1">See also <a class="header-anchor" href="#See-also" aria-label="Permalink to &quot;See also {#See-also}&quot;">​</a></h2><ul><li><p><a href="./relmat-known-matrices">Known-matrix relatedness with relmat</a></p></li><li><p><a href="./animal-models">Animal models and additive relatedness</a></p></li><li><p><a href="./phylogenetic-models">Phylogenetic structured effects</a></p></li><li><p><a href="./spatial-models">Coordinate-spatial structured effects</a></p></li></ul>',7)])])}const g=t(o,[["render",l]]);export{h as __pageData,g as default};
